import React, { useState } from 'react';
import { NavLink, Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../../context/AuthContext';

const Navbar = () => {
  const { user, logout } = useAuth();
  const navigate = useNavigate();
  const [dropdownOpen, setDropdownOpen] = useState(false);

  const onLogout = () => {
    logout();
    setDropdownOpen(false);
    navigate('/');
  };

  const activeLinkStyle = {
    color: '#124170', // Using your brand-dark-blue
    fontWeight: 'bold',
  };

  const authLinks = (
    <div className="relative">
      <button onClick={() => setDropdownOpen(!dropdownOpen)} className="flex items-center justify-center w-10 h-10 bg-white/20 rounded-full text-white font-bold text-lg focus:outline-none focus:ring-2 focus:ring-white">
        {user ? user.name.charAt(0).toUpperCase() : '?'}
      </button>

      {dropdownOpen && (
        <div className="absolute right-0 mt-2 w-48 bg-white rounded-lg shadow-xl py-2 z-50">
          <NavLink 
            to="/dashboard" 
            className="block px-4 py-2 text-gray-800 hover:bg-gray-100"
            style={({ isActive }) => isActive ? activeLinkStyle : undefined}
            onClick={() => setDropdownOpen(false)}
          >
            Dashboard
          </NavLink>
          <button 
            onClick={onLogout} 
            className="w-full text-left block px-4 py-2 text-gray-800 hover:bg-gray-100"
          >
            Logout
          </button>
        </div>
      )}
    </div>
  );

  const guestLinks = (
    <>
      <li><NavLink to="/login" className="text-brand-teal hover:text-brand-dark-blue transition-colors" style={({ isActive }) => isActive ? {color: '#124170', fontWeight: 'bold'} : undefined}>Login</NavLink></li>
      <li><Link to="/signup" className="bg-brand-green text-white px-4 py-2 rounded-lg hover:bg-opacity-90 transition-colors shadow-sm font-bold">Sign Up</Link></li>
    </>
  );

  return (
    <nav className="bg-white/80 backdrop-blur-md shadow-sm sticky top-0 z-50">
      <div className="container mx-auto flex justify-between items-center p-4">
        <Link to="/" className="flex items-center gap-2">
          {/* Simple SVG Leaf Icon */}
          <svg xmlns="http://www.w3.org/2000/svg" width="28" height="28" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" className="text-brand-green"><path d="M11 20A7 7 0 0 1 4 13H2a10 10 0 0 0 10 10v-3Z"></path><path d="M13 4a7 7 0 0 1 7 7h2a10 10 0 0 0-10-10v3Z"></path><path d="M7.7 7.7A5.99 5.99 0 0 1 12 6v6l-4.3 4.3"></path></svg>
          <h1 className="text-2xl font-bold text-brand-green">
            NutriSync
          </h1>
        </Link>
        <ul className="flex space-x-6 items-center font-medium">
          {user ? authLinks : guestLinks}
        </ul>
      </div>
    </nav>
  );
};

export default Navbar;
